import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                m[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return m

b = build_map(baseline)
a = build_map(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))
changes = []
unchanged = []
for k in all_keys:
    bv = b.get(k)
    av = a.get(k)
    if bv != av:
        changes.append((k[0], k[1], k[2], bv or 'N/A', av or 'N/A'))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]:15s} {c[1]:8s} {c[2]:50s} {c[3]:10s} -> {c[4]}')
else:
    print('  None')

print()
print(f'=== UNCHANGED ({len(unchanged)} packages) ===')
for u in unchanged:
    print(f'  {u[0]:15s} {u[1]:8s} {u[2]:50s} {u[3]}')
"

